}

// ---------- EVENTS ----------
abstract class SearchEvent extends Equatable {
  const SearchEvent();
  @override
  List<Object?> get props() => [];
}

class SearchQueryChanged extends SearchEvent {
  final String query;
  const SearchQueryChanged(this.query);
  @override
  List<Object?> get props => [query];
}

// ---------- TRANSFORMER ----------
EventTransformer<Event> debounce<Event>(Duration duration) {
  return (events, mapper) => events.debounceTime(duration).flatMap(mapper);
}

// ---------- BLOC ----------
class SearchBloc extends Bloc<SearchEvent, SearchState> {
  final SearchRepository repository;

  SearchBloc({required this.repository}) : super(SearchInitial()) {
    on<SearchQueryChanged>(
      _onSearchQueryChanged,
      transformer: debounce(const Duration(milliseconds: 500)),
    );
  }

  Future<void> _onSearchQueryChanged(
    SearchQueryChanged event,
    Emitter<SearchState> emit,
  ) async {
    if (event.query.isEmpty) {
      emit(SearchInitial());
      return;
    }
    emit(SearchLoading());
    try {
      final results = await repository.search(event.query);
      emit(SearchSuccess(results));
    } catch (e) {
      emit(SearchError(e.toString()));
    }
  }
}

// ---------- REPOSITORY ----------
abstract class SearchRepository {
  Future<List<String>> search(String query);
}

class MockSearchRepository implements SearchRepository {
  @override
  Future<List<String>> search(String query) async {
    // Simulate network delay
    await Future.delayed(const Duration(milliseconds: 300));
    if (query.startsWith('error')) {
      throw Exception('Mock error');
    }
    return [
      '$query result 1',
      '$query result 2',
      '$query result 3',
    ];
  }
}

// ---------- UI ----------
class SearchPage extends StatelessWidget {
  final TextEditingController controller = TextEditingController();

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Search with Debounce')),
      body: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          children: [
            TextField(
              controller: controller,
              decoration: InputDecoration(
                labelText: 'Search (500ms debounce)',
                prefixIcon: Icon(Icons.search),
                border: OutlineInputBorder(),
              ),
              onChanged: (value) {
                context.read<SearchBloc>().add(SearchQueryChanged(value));
              },
            ),
            const SizedBox(height: 20),
            Expanded(
              child: BlocBuilder<SearchBloc, SearchState>(
                builder: (context, state) {
                  if (state is SearchInitial) {
                    return Center(child: Text('Start typing...'));
                  } else if (state is SearchLoading) {
                    return Center(child: CircularProgressIndicator());
                  } else if (state is SearchSuccess) {
                    return ListView.builder(
                      itemCount: state.results.length,
                      itemBuilder: (_, index) => ListTile(
                        title: Text(state.results[index]),
                      ),
                    );
                  } else if (state is SearchError) {
                    return Center(child: Text('Error: ${state.message}'));
                  }
                  return Container();
                },
              ),
            ),
          ],
        ),
      ),
    );
  }
}
